     1→import { useQuery, useQueryClient } from "@tanstack/react-query";
     2→import { useLocation } from "react-router-dom";
     3→import { addReplyOpinion, getViewOpinion } from "../../../API/Api";
     4→import { useAuth } from "../../Context/useAuth";
     5→import { useEffect } from "react";
     6→import { useState } from "react";
     7→import { useRef } from "react";
     8→import OpinionsReplyCard from "./OpinionsCardRepy";
     9→
    10→const OpinionViewer = () =>{
    11→    const queryClient = useQueryClient();
    12→    const location = useLocation();
    13→    const {opinionId, userId} = location.state;
    14→    const {user} = useAuth();
    15→    const textAreaRef = useRef(null);
    16→
    17→    const [replyOpinion, setReplyOpinion] = useState('');
    18→    const [isTyping, setIsTyping] = useState(false);
    19→
    20→    const {data, isLoading} = useQuery({
    21→        queryKey: ['getViewOpinion', opinionId, userId],
    22→        queryFn: ({queryKey}) => getViewOpinion(queryKey[1], queryKey[2]),
    23→        staleTime: 1000 * 60 * 60,
    24→        cacheTime: 1000 * 60 * 60,
    25→        enabled: !!opinionId && !!userId,
    26→        refetchOnWindowFocus: false
    27→    })
    28→
    29→    const cancelTyping = (e) =>{
    30→        setIsTyping(false)
    31→        setReplyOpinion('')
    32→        if(textAreaRef.current){            
    33→            textAreaRef.current.innerText = ''
    34→            //remove the textarea focus
    35→            textAreaRef.current.blur();
    36→        }
    37→    }
    38→
    39→    const submitReply = async(opinionId, receiverId, senderId, parentId)=>{
    40→        console.log(replyOpinion);
    41→        const formData = new FormData();
    42→        formData.append('opinion', replyOpinion);
    43→
    44→        try {
    45→            const res = await addReplyOpinion(formData, opinionId, receiverId, senderId, parentId);
    46→            if(res){
    47→                console.log(res);
    48→            }
    49→            setReplyOpinion('')
    50→            if(textAreaRef.current){
    51→            textAreaRef.current.innerText = ''
    52→            queryClient.invalidateQueries(['getViewOpinion', opinionId, receiverId])
    53→        }
    54→        } catch (error) {
    55→            console.error(error);
    56→            setReplyOpinion('')
    57→            if(textAreaRef.current){
    58→                textAreaRef.current.innerText = ''
    59→            }
    60→            queryClient.invalidateQueries(['getViewOpinion', opinionId, receiverId])
    61→            //invalidateQueries the query of the reply cards component where the recursive happens so it will update the data lived there
    62→        }
    63→    }
    64→
    65→
    66→    const opinionData = data?.data;
    67→    return(
    68→        <>
    69→        {opinionData?.map((opinion) => (
    70→            <div className="opinion-viewer-parent-container" key={opinion.id}>
    71→                <div className="opinion-user-data-card">
    72→                    <img className="opinion-user-profile" src={opinion.users.image_url || '../assets/profile.jpg'} alt="" />
    73→                    <p>{opinion.users.name} <span className="opinion-user-email">@{opinion.users.user_email}</span></p>
    74→                </div>
    75→                <div className="opinion-content-card">
    76→                    {opinion.opinion}
    77→                </div>
    78→
    79→                <div className="opinion-metadata">
    80→                    <p>{opinion.reply_count} replies</p>
    81→                    <p>∙</p>
    82→                    <p>
    83→                        {new Date(opinion.created_at).toLocaleDateString('en-US',{
    84→                            month: 'long',
    85→                            day: '2-digit',
    86→                            year: 'numeric',
    87→                        })} at {new Date(opinion.created_at).toLocaleTimeString('en-US',{
    88→                            hour: 'numeric'
    89→                        })}
    90→                    </p>
    91→                </div>
    92→
    93→                <div className="add-opinion-reply-container">
    94→                    <img className="opinion-user-profile-add-reply" src={user?.userData[0].image_url || '../assets/profile.jpg'} alt="" />
    95→                    <div onFocus={() => setIsTyping(true)} ref={textAreaRef} value={replyOpinion} onInput={(e) => setReplyOpinion(e.currentTarget.innerText.trim())} data-placeholder={`Add a reply to '${opinion.users.name}'`} className="opinion-reply-area" contentEditable='true' role="textarea"></div>
    96→                </div>
    97→
    98→                {isTyping && (
    99→                    <div className="submit-buttn-container">
   100→                        <button onClick={(e) => cancelTyping(e)} className="cancel">Cancel</button>
   101→                        <button disabled={replyOpinion.trim().length === 0} onClick={() => submitReply(opinionId, userId, user?.userData[0].id, opinion.id)} className={replyOpinion.trim().length === 0 ? "submit-disabled" : "submit"}>Submit</button> 
   102→                    </div>
   103→                )}
   104→                
   105→                <OpinionsReplyCard opinionId={opinion.id}/>
   106→            </div>
   107→        ))}
   108→        </>
   109→    )
   110→}
   111→export default OpinionViewer;

