    13→
    14→    const [showReplyButtonId, setShowReplyButtonId] = useState('')
    15→
    16→    const textAreaRef = useRef(null);
    17→
    18→    const {data, isLoading, hasNextPage, isFetchingNextPage, fetchNextPage} = useInfiniteQuery({
    19→        queryKey: ['getReplyOpinion', opinionId],
    20→        queryFn: ({queryKey, pageParam = null}) => getOpinionReply(queryKey[1], 10, pageParam),
    21→        getNextPageParam: (lastPage) => {
    22→            if(lastPage?.hasMore){
    23→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
    24→                return lastReply.id;
    25→            } else {
    26→                return undefined;
    27→            }
    28→        },
    29→        enabled: !!opinionId,
    30→        refetchOnWindowFocus: false
    31→    })
    32→
    33→    const handleSubmitRelyOpinion = async(reply, receiver_id, sender_id, parent_id) =>{
    34→        try {
    35→             const formadata = new FormData();
    36→
    37→            formadata.append('opinion', reply)
    38→            const response = await addReplyOpinion(formadata, receiver_id, sender_id, parent_id);
    39→            if(response){
    40→                console.log(response);
    41→            }
    42→            queryClient.invalidateQueries(['getReplyOpinion', opinionId]);
    43→            setReplyOpinion('');
    44→            if(textAreaRef.current){
    45→                textAreaRef.current.innerText = '';
    46→            }
    47→        } catch (error) {
    48→            console.error(error);
    49→            setReplyOpinion('');
    50→            if(textAreaRef.current){
    51→                textAreaRef.current.innerText = '';
    52→            }
    53→            queryClient.invalidateQueries(['getReplyOpinion', opinionId]);
    54→        }
    55→    }
    56→
    57→    const cancelTyping = (e) =>{
    58→        setIsTypingId('')
    59→        setReplyOpinion('')
    60→        
    61→        if(textAreaRef.current){            
    62→            textAreaRef.current.innerText = ''
    63→            //remove the textarea focus
    64→            textAreaRef.current.blur();
    65→        }
    66→        setShowReplyButtonId('')
    67→    }
    68→
    69→    useEffect(() =>{
    70→        console.log(data)
    71→    }, [data])
    72→
    73→    const opinioData = data?.pages.flatMap((page) => page.data) || [];
    74→    return (
    75→        <>
    76→        {opinioData?.map((opinion) => (
    77→            <div key={opinion.id} className="reply-cards">
    78→                {opinion.opinion}
    79→
    80→                <div className="reply-count">
    81→                    {opinion.reply_count}
    82→                </div>
    83→
    84→                {opinion.reply_count > 0 && (
    85→                    <button onClick={() => setShowReply(true)}>{showReply ? 'Hide replies' : 'Show replies'} {opinion.reply_count}</button>
    86→                )}
    87→
    88→                {showReply && (
    89→                    <OpinionsReplyCard opinionId={opinion.id} key={opinion.id}/>
    90→                )}
    91→
    92→                {showReplyButtonId === opinion.id && (
    93→                    <div onFocus={() => setIsTypingId(opinion.id)} ref={textAreaRef} value={replyOpinion} onInput={(e) => setReplyOpinion(e.currentTarget.innerText.trim())} className="opinion-reply-area" contentEditable='true' role="textarea"  data-placeholder={`Add a reply to '${opinion.users.name}'`}>
    94→
    95→                    </div>
    96→                )}
    97→
    98→                <button onClick={() => setShowReplyButtonId(opinion.id)}>Reply</button>
    99→
   100→                {isTypingId === opinion.id && (
   101→                    <div className="submit-buttn-container">
   102→                        <button onClick={(e) => cancelTyping(e)} className="cancel">Cancel</button>
   103→                        <button disabled={replyOpinion.trim().length === 0} onClick={() => handleSubmitRelyOpinion(replyOpinion, opinion.users.id, user?.userData[0].id, opinion.id )} className={replyOpinion.trim().length === 0 ? "submit-disabled" : "submit"}>Submit</button> 
   104→                    </div>
   105→                )}
   106→
   107→            </div>
   108→        ))}
   109→        {hasNextPage &&(
   110→            <div>
   111→                Show more
   112→            </div>
   113→        )}
   114→        
   115→        </>
   116→    )
   117→}
   118→export default OpinionsReplyCard;

